import{_ as s,o as a,c as e,Q as n}from"./chunks/framework.3daba8ea.js";const b=JSON.parse('{"title":"ENTRYPOINT","description":"","frontmatter":{},"headers":[],"relativePath":"doc/DevOps/Docker/Dockerfile/ENTRYPOINT.md","filePath":"packages/doc/src/DevOps/Docker/Dockerfile/ENTRYPOINT.md","lastUpdated":1703174217000}'),p={name:"doc/DevOps/Docker/Dockerfile/ENTRYPOINT.md"},l=n(`<h1 id="entrypoint" tabindex="-1">ENTRYPOINT <a class="header-anchor" href="#entrypoint" aria-label="Permalink to &quot;ENTRYPOINT&quot;">​</a></h1><p><a href="https://zhuanlan.zhihu.com/p/548188679" target="_blank" rel="noreferrer">https://zhuanlan.zhihu.com/p/548188679</a> 该指令同样可以用于指定容器被启动时需要运行的命令。同理，其同样支持shell、exec两种形式的语法</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># shell格式</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT command  param1 param2</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;"># exec格式</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># shell格式</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT command  param1 param2</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;"># exec格式</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT [&quot;command&quot;, &quot;param1&quot;, &quot;param1&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>对于ENTRYPOINT指令而言，Docker中同样推荐使用exec格式语法，理由与CMD指令同理。 ENTRYPOINT指令 所设置命令、参数可被 docker run命令行参数中指定要运行的命令 覆盖, 但需要使用 --entrypoint 选项进行显式覆盖。否则将会忽略命令行参数</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># 错误方式</span></span>
<span class="line"><span style="color:#e1e4e8;">docker run --name demo3B --rm -it demo3:test ifconfig</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;"># 正确方式</span></span>
<span class="line"><span style="color:#e1e4e8;">docker run --name demo3C --rm -it --entrypoint ifconfig demo3:test</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># 错误方式</span></span>
<span class="line"><span style="color:#24292e;">docker run --name demo3B --rm -it demo3:test ifconfig</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;"># 正确方式</span></span>
<span class="line"><span style="color:#24292e;">docker run --name demo3C --rm -it --entrypoint ifconfig demo3:test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="entrypoint和cmd区别" tabindex="-1">entrypoint和CMD区别 <a class="header-anchor" href="#entrypoint和cmd区别" aria-label="Permalink to &quot;entrypoint和CMD区别&quot;">​</a></h2><p>cmd是容器默认的执行，entrypoint是容器正真的执行命令，会覆盖CMD cmd可以作为entrypoint的默认参数</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">The CMD instruction has three forms:</span></span>
<span class="line"><span style="color:#e1e4e8;">CMD [&quot;executable&quot;,&quot;param1&quot;,&quot;param2&quot;] (exec form, this is the preferred form)</span></span>
<span class="line"><span style="color:#e1e4e8;">CMD [&quot;param1&quot;,&quot;param2&quot;] (as default parameters to ENTRYPOINT)</span></span>
<span class="line"><span style="color:#e1e4e8;">CMD command param1 param2 (shell form)</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT has two forms:</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT [&quot;executable&quot;, &quot;param1&quot;, &quot;param2&quot;] (exec form, preferred)</span></span>
<span class="line"><span style="color:#e1e4e8;">ENTRYPOINT command param1 param2 (shell form)</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">The CMD instruction has three forms:</span></span>
<span class="line"><span style="color:#24292e;">CMD [&quot;executable&quot;,&quot;param1&quot;,&quot;param2&quot;] (exec form, this is the preferred form)</span></span>
<span class="line"><span style="color:#24292e;">CMD [&quot;param1&quot;,&quot;param2&quot;] (as default parameters to ENTRYPOINT)</span></span>
<span class="line"><span style="color:#24292e;">CMD command param1 param2 (shell form)</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT has two forms:</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT [&quot;executable&quot;, &quot;param1&quot;, &quot;param2&quot;] (exec form, preferred)</span></span>
<span class="line"><span style="color:#24292e;">ENTRYPOINT command param1 param2 (shell form)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div>`,8),o=[l];function r(t,c,i,m,u,d){return a(),e("div",null,o)}const y=s(p,[["render",r]]);export{b as __pageData,y as default};
